class Solution {
    public long minimumSteps(String s) {
        int n = s.length();
        int[] rightZeros = new int[n];
        int countZero = 0;

        for (int i = n - 1; i >= 0; i--) {
            rightZeros[i] = countZero;
            if (s.charAt(i) == '0') {
                countZero++;
            }
        }

        long total = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '1') {
                total += rightZeros[i];
            }
        }

        return total;
    }
}

